proof_block:
// The ensures of `det_page_perm_to_page_map` is an implication
//
//   (big_conj on r1 and r2) ==> det_page_perm_to_page_map_equal(r1, r2)
//
// not the unconditional conclusion.  The previous attempt asserted the
// scalar pieces of the conclusion (e.g. `r1.0 == page_ptr`) directly,
// which Verus rejected because none of those facts are free hypotheses
// of the proof body — they are merely the antecedent of the ensures.
//
// Wrap the proof in a spec-level `if` on the antecedent so each
// conjunct becomes a local hypothesis.  In the false branch the
// postcondition holds vacuously; in the true branch we discharge it
// component-by-component.
if r1.0 == page_ptr
    && (r1.1@).addr() == r1.0
    && (r1.1@).is_init()
    && (r1.1@).value().wf()
    && (forall|i: usize|
        #![trigger (r1.1@).value()[i].is_empty()]
        0 <= i < 512 ==> (r1.1@).value()[i].is_empty())
    && r2.0 == page_ptr
    && (r2.1@).addr() == r2.0
    && (r2.1@).is_init()
    && (r2.1@).value().wf()
    && (forall|i: usize|
        #![trigger (r2.1@).value()[i].is_empty()]
        0 <= i < 512 ==> (r2.1@).value()[i].is_empty())
{
    // -- Scalar conjuncts of det_page_perm_to_page_map_equal -----------
    assert(r1.0 == page_ptr);
    assert(r2.0 == page_ptr);
    assert(r1.0 == r2.0);

    assert((r1.1@).is_init());
    assert((r2.1@).is_init());
    assert((r1.1@).is_init() == (r2.1@).is_init());

    assert((r1.1@).addr() == r1.0);
    assert((r2.1@).addr() == r2.0);
    assert((r1.1@).addr() == (r2.1@).addr());

    // -- PageMap.wf() gives spec_seq@.len() == 512 on both sides --------
    assert((r1.1@).value().wf());
    assert((r2.1@).value().wf());
    assert((r1.1@).value().spec_seq@.len() == 512);
    assert((r2.1@).value().spec_seq@.len() == 512);

    // -- Force both `forall|i| ... .is_empty()` ensures to fire with
    //    triggers matching each candidate.  Without this, the two
    //    foralls have disjoint triggers (one keyed on r1.1, one on
    //    r2.1), so z3 never lines them up.
    assert(forall|i: usize|
        #![trigger (r1.1@).value()[i].is_empty()]
        0 <= i < 512 ==> (r1.1@).value()[i].is_empty());
    assert(forall|i: usize|
        #![trigger (r2.1@).value()[i].is_empty()]
        0 <= i < 512 ==> (r2.1@).value()[i].is_empty());

    // -- Pointwise spec_seq equality.  PageEntry::is_empty() unfolds
    //    to a conjunction pinning every field of the entry (addr == 0,
    //    perm.present == false, perm.ps == false, perm.write == false,
    //    perm.execute_disable == false, perm.user == false), so any
    //    two PageEntries that are both is_empty() must agree on every
    //    field.  Combined with PageMap::spec_index returning the
    //    spec_seq entry, this lifts to spec_seq@[i] equality.
    assert forall|i: int| 0 <= i < 512 implies
        (r1.1@).value().spec_seq@[i] == (r2.1@).value().spec_seq@[i] by {
        let iu = i as usize;
        assert(0 <= iu < 512);

        // Fire each forall on the same index.
        assert((r1.1@).value()[iu].is_empty());
        assert((r2.1@).value()[iu].is_empty());

        // PageMap::spec_index(iu) == spec_seq@[iu as int].
        assert((r1.1@).value()[iu] == (r1.1@).value().spec_seq@[iu as int]);
        assert((r2.1@).value()[iu] == (r2.1@).value().spec_seq@[iu as int]);
        assert(iu as int == i);

        let e1 = (r1.1@).value().spec_seq@[i];
        let e2 = (r2.1@).value().spec_seq@[i];
        assert(e1 == (r1.1@).value()[iu]);
        assert(e2 == (r2.1@).value()[iu]);
        assert(e1.is_empty());
        assert(e2.is_empty());

        // All fields pinned by is_empty().
        assert(e1.addr == 0);
        assert(e2.addr == 0);
        assert(e1.perm.present == false);
        assert(e2.perm.present == false);
        assert(e1.perm.ps == false);
        assert(e2.perm.ps == false);
        assert(e1.perm.write == false);
        assert(e2.perm.write == false);
        assert(e1.perm.execute_disable == false);
        assert(e2.perm.execute_disable == false);
        assert(e1.perm.user == false);
        assert(e2.perm.user == false);

        // Struct extensionality on PageEntryPerm and PageEntry.
        assert(e1.perm =~= e2.perm);
        assert(e1 =~= e2);
    }

    // -- Lift pointwise spec_seq equality to Seq extensionality.
    assert((r1.1@).value().spec_seq@ =~= (r2.1@).value().spec_seq@);
    assert((r1.1@).value().spec_seq@ == (r2.1@).value().spec_seq@);

    // -- PageMapView equality.  PageMapView is a struct with fields
    //    `ar: Array<usize, 512>` and `spec_seq: Seq<PageEntry>`.
    //    Apply struct extensionality through `=~=` and then `==`.
    assert((r1.1@).value().view() =~= (r2.1@).value().view());
    assert((r1.1@).value().view() == (r2.1@).value().view());
}
